const ADD_POST = "ADDPOST";
const NEW_POST = "NEWPOST";

type InitialStateType = {
  messegData: Array<string>,
  newChanges: string,
  id: number,
}
const initialState: InitialStateType = {
  messegData: [],
  newChanges: "",
  id: 0
};
const messegDataReducer = (state = initialState, action: any): InitialStateType => {
  let copy;
  switch (action.type) {
    case NEW_POST: {
      copy = { ...state, newChanges: action.newChange };
      return copy;
    }
    case ADD_POST:
      if (state.newChanges === "") {
        return state;
      }
      copy = {
        ...state,
        messegData: [
          ...state.messegData,
          {
            id: 5,
            messege: state.newChanges,
          },
        ],
        newChanges: "",
      };
      return copy;
    default:
      return state;
  }
};
type addPostcreateActinType = {
  type: typeof ADD_POST
};
export const addPostcreateActin = (): addPostcreateActinType => ({ type: ADD_POST });

export const onPostChangecreateActin = (text: string) => ({
  type: NEW_POST,
  newChange: text,
});
export default messegDataReducer;
